import{c as t,Q as r,j as a,m as l}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Claude Code Skills 合集精選 8 個 — @qloog","description":"","frontmatter":{"title":"Claude Code Skills 合集精選 8 個 — @qloog","author":"Richard（@qloog）","date":"2026-04-21T00:00:00.000Z","source":"https://x.com/qloog/status/2046394883724992742","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-21-@qloog-992742.md","filePath":"research/tweets/2026-04-21-@qloog-992742.md","lastUpdated":1779894392000}'),o={name:"research/tweets/2026-04-21-@qloog-992742.md"};function s(i,e,n,d,h,c){return r(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="claude-code-skills-合集精選-8-個-—-qloog" tabindex="-1">Claude Code Skills 合集精選 8 個 — @qloog <a class="header-anchor" href="#claude-code-skills-合集精選-8-個-—-qloog" aria-label="Permalink to &quot;Claude Code Skills 合集精選 8 個 — @qloog&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/qloog/status/2046394883724992742" target="_blank" rel="noreferrer">https://x.com/qloog/status/2046394883724992742</a><strong>作者</strong>：Richard（@qloog） <strong>發布日期</strong>：2026-04-21 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文 <strong>統計</strong>：651 likes · 149 retweets · 821 bookmarks · 41,228 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>#每日推荐 Claude Code Skills 合集， 也适用于 OpenClaw 和 Hermes</p><p>1）superpowers（16 万星） 作者 Jesse Vincent，适合所有人，让 Claude 做事更严谨。 <a href="http://github.com/obra/superpowers" target="_blank" rel="noreferrer">http://github.com/obra/superpowers</a></p><p>2）anthropics/skills（12 万星） Anthropic 官方，适合所有人，文件处理（Word、PPT、Excel、PDF）。 <a href="http://github.com/anthropics/skills" target="_blank" rel="noreferrer">http://github.com/anthropics/skills</a></p><p>3）gstack（7.7 万星） 作者 Garry Tan（YC CEO），适合一人公司，用来模拟团队角色进行审查。 <a href="http://github.com/garrytan/gstack" target="_blank" rel="noreferrer">http://github.com/garrytan/gstack</a></p><p>4）obsidian-skills（2.5 万星） 作者 Steph Ango（Obsidian CEO），适合 Obsidian 用户。 <a href="http://github.com/kepano/obsidian-skills" target="_blank" rel="noreferrer">http://github.com/kepano/obsidian-skills</a></p><p>5）claude-code-templates（2.5 万星） 作者 Daniel Ávila，适合 skill 新手的大型工具集。 <a href="http://github.com/davila7/claude-code-templates" target="_blank" rel="noreferrer">http://github.com/davila7/claude-code-templates</a></p><p>6）marketingskills（2.2 万星） 作者 Corey Haines，适合营销、副业和一人公司。 <a href="http://github.com/coreyhaines31/marketingskills" target="_blank" rel="noreferrer">http://github.com/coreyhaines31/marketingskills</a></p><p>7）claude-scientific-skills（1.9 万星） 作者 K-Dense AI，适合科研、论文写作和深度内容创作。 <a href="http://github.com/K-Dense-AI/claude-scientific-skills" target="_blank" rel="noreferrer">http://github.com/K-Dense-AI/claude-scientific-skills</a></p><p>8）compound-engineering-plugin（1.5 万星） 作者 Every.to 团队，适合长期内容或产品运营。 <a href="http://github.com/EveryInc/compound-engineering-plugin" target="_blank" rel="noreferrer">http://github.com/EveryInc/compound-engineering-plugin</a></p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：8 個高星標 Claude Code Skills 精選清單，按使用情境分類，涵蓋全能型、檔案處理、團隊角色模擬、Obsidian、行銷、科研等面向。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Skills 生態已有成熟的分類——不同職業/情境有對應的 Skills，而非一套適用所有人</li><li>星標數量級懸殊（superpowers 16萬 vs compound-engineering 1.5萬），頭部 Skills 壟斷效應明顯</li><li>名人背書效應：Garry Tan（YC CEO）、Steph Ango（Obsidian CEO）都有自己的 Skills——生態正向主流開發者蔓延</li><li>跨工具相容性（OpenClaw、Hermes）說明 Claude Skills 格式已開始成為標準</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>superpowers（obra）：16萬星，讓 Claude 做事更嚴謹，brainstorm→spec→plan→TDD→review→merge</li><li>anthropics/skills：12萬星，官方文件處理（Word/PPT/Excel/PDF）</li><li>gstack（Garry Tan）：7.7萬星，模擬團隊角色進行審查</li><li>obsidian-skills（Steph Ango）：2.5萬星，Obsidian 使用者專用</li><li>claude-scientific-skills（K-Dense AI）：1.9萬星，科研/論文寫作</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>星標數字明顯誇大（superpowers 原始 repo 約 16-18 萬星是可信的，但 gstack 7.7 萬星需要交叉驗證）</li><li>清單缺乏使用者驗證的質量評估，純以星標數作為排序指標</li><li>「适用于 OpenClaw 和 Hermes」的相容性聲明未提供任何設定說明</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>提供具體 GitHub URLs，superpowers 和 anthropics/skills 可立即安裝到本 workspace 補強；本 workspace 已有 <code>.claude/skills/</code> 但官方 Skills 尚未整合</td></tr><tr><td>B. 創新性 (20%)</td><td>4/10</td><td>清單彙整，無原創分析；但名人背書和使用情境分類有一定篩選價值</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>有具體 GitHub URLs 和星標數，可驗證；但星標數可能誇大，缺乏使用評測</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>每個 Skills 只有 1-2 句描述，無安裝指令、技術差異或使用案例</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>覆蓋多種使用情境（全能/檔案/科研/行銷），適用範圍廣</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.35/10</strong></td><td>7×0.3 + 4×0.2 + 5×0.2 + 3×0.15 + 7×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：清單資訊已大量重疊於既有推文（如 0x_kaize 的 100 repos），且技術深度不足以直接轉化為 Skill 或 Rule；可作為 Skills 安裝時的參考清單但不需獨立歸檔行動</p>',26)])])}const u=t(o,[["render",s]]);export{g as __pageData,u as default};
